pub enum GcArgs {
    Stop,
    Restart,
    Collect,
    Count,
    CountB,
    Step { data: i32 },
    SetPause { value: i32 },
    SetStepMul { value: i32 },
    IsRunning,
    Gen { minormul: i32, majormul: i32 },
    Inc { pause: i32, stepmul: i32, stepsize: i32 },
