1	//! Phase-D `Trace` implementations for GC-rooted types defined in this
2	//! crate. Types in `lua-types` (LuaValue, LuaString, UpVal) have their
3	//! Trace impls in `lua-types/src/trace_impls.rs` because of Rust's orphan
4	//! rule.
5	//!
6	//! Each impl below is a `todo!("phase-d: trace X")` stub. The
7	//! panic-driven mega-loop surfaces each one when a runtime path triggers
8	//! `Heap::full_collect`. Each agent works on ONE type — no family
9	//! expansion (Trace impls have subtle invariants).
10	//!
11	//! Implementation guidance for agents:
12	//!   1. Read the type definition; enumerate every field
13	//!   2. For every `Gc<T>`, `GcRef<T>`, or container (Vec/Option/HashMap)
14	//!      thereof, call `m.mark(field)` or `field.trace(m)` appropriately
15	//!   3. Skip non-GC fields (primitives, `String`, `Vec<u8>`)
16	//!   4. Skip "intentionally not traced" fields (weak refs)
17	//!   5. Reference `reference/lua-5.4.7/src/lgc.c`'s `reallymarkobject`
18	
19	use lua_gc::{Marker, Trace};
20	use crate::state::{LuaState, GlobalState};
21	
22	impl Trace for LuaState {
23	    fn trace(&self, m: &mut Marker) {
24	        // C: `traversethread` in lgc.c walks the live portion of the stack
25	        // (`stack..top`) and the open-upvalue list. Slots past `top` are
26	        // dead and must not be visited.
27	        let top = self.top.0 as usize;
28	        let end = top.min(self.stack.len());
29	        for slot in &self.stack[..end] {
30	            slot.val.trace(m);
31	        }
32	
33	        for uv in self.openupval.iter() {
34	            uv.trace(m);
35	        }
36	
37	        // PORT NOTE: `global` (Rc<RefCell<GlobalState>>) is reached from the
38	        // heap's root via GlobalState::trace; tracing it from each thread
39	        // would re-enter the root and is explicitly excluded.
40	        // PORT NOTE: `call_info` entries carry pc offsets and stack indices
41	        // but no direct GcRef fields. The active closure is reached through
42	        // the stack slot at `ci.func`, already covered by the stack walk.
43	        // PORT NOTE: `tbclist` holds StackIdx values only; the to-be-closed
44	        // objects themselves live on the stack and are traced there.
45	    }
46	}
47	
48	impl Trace for GlobalState {
49	    fn trace(&self, m: &mut Marker) {
50	        // C: `restartcollection` in lgc.c marks mainthread, l_registry, the
51	        // per-type metatables, and pending finalizers. We expand the set to
52	        // include preallocated short strings (memerrmsg, tmname[]) and the
53	        // open-upvalue thread list, both of which the panic-driven Phase-D
54	        // mega-loop expects to see at the root.
55	
56	        self.l_registry.trace(m);
57	
58	        if let Some(t) = &self.mainthread {
59	            t.trace(m);
60	        }
61	
62	        for slot in self.mt.iter() {
63	            if let Some(t) = slot {
64	                t.trace(m);
65	            }
66	        }
67	
68	        for s in self.tmname.iter() {
69	            s.trace(m);
70	        }
71	
72	        self.memerrmsg.trace(m);
73	
74	        for th in self.twups.iter() {
75	            th.trace(m);
76	        }
77	
78	        // PORT NOTE: `strt` (intern table) is a weak table in C; entries are
79	        // cleared during the atomic weak-table pass (`clearbykeys`), not
80	        // marked as roots. Same for `strcache` and `interned_lt`.
81	        // PORT NOTE: `fixedgc` holds objects pre-marked fixed/black at
82	        // allocation (`luaC_fix`); the mark phase never re-visits them, and
83	        // `dyn Collectable` does not implement `Trace` here.
84	        // PORT NOTE: `allgc`, `finobj`, `gray`, `grayagain`, `tobefnz`,
85	        // `weak`, `ephemeron`, `allweak` are GC bookkeeping lists owned by
86	        // `heap` — they are the universe of allocated objects, not roots.
