/// Garbage collector operating mode.
///
/// C: `KGC_INC` / `KGC_GEN` constants in `lstate.h`.
/// macros.tsv: `KGC_INC → GcKind::Incremental`, `KGC_GEN → GcKind::Generational`
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum GcKind {
    // C: KGC_INC = 0
    Incremental = 0,
    // C: KGC_GEN = 1
    Generational = 1,
}

