    pub gcpause: u8,

    // C: lu_byte gcstepmul — GC speed (/4 stored)
    // types.tsv: global_State.gcstepmul → u8
    pub gcstepmul: u8,

    // C: lu_byte gcstepsize — log2 of GC granularity
    pub gcstepsize: u8,

    // C: GCObject *allgc — all collectable objects; Phase A–C leaks (Rc cycles)
