    let o = index_to_value(state, idx);
    matches!(o, LuaValue::Str(_) | LuaValue::Int(_) | LuaValue::Float(_))
}

// C: LUA_API int lua_isuserdata (lua_State *L, int idx)
pub fn is_userdata(state: &LuaState, idx: i32) -> bool {
